import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule }  from '@angular/forms';

import { BrlPipe }                   from '../../shared/pipes/brl.pipe';
import { ToastService }              from 'src/app/shared/components/toast/toast.service';
import { PresenteRecebidoDTO }       from '../presente-recebido/presente-recebido.model';
import { PresenteRecebidoService }   from '../presente-recebido/presente-recebido.service';
import { ConviteResponse, Convidado } from '../convite/convite.model';
import { AuthService }               from './auth.service';
import { ConviteService }            from '../convite/convite.service';
import { CatalogoPresente, CatalogoPresenteForm } from '../catalogo-presente/catalogo-presente.model';
import { CatalogoPresenteService }   from '../catalogo-presente/catalogo-presente.service';
import { AdminLoginRequest, ConviteAdminRequest } from './admin.model';

type AdminTab = 'dashboard' | 'catalogo' | 'presentes' | 'presencas' | 'mensagens' | 'convites';

@Component({
  selector: 'app-admin',
  standalone: true,
  imports: [CommonModule, FormsModule, BrlPipe],
  templateUrl: './admin.component.html',
  styleUrls: ['./admin.component.scss'],
})
export class AdminComponent implements OnInit {

  // ── Auth ──────────────────────────────────
  loginUser = '';
  loginPass = '';
  loginErr  = '';
  logging   = false;

  // ── Tab ───────────────────────────────────
  activeTab: AdminTab = 'dashboard';

  // ── Catálogo ──────────────────────────────
  catalogo:      CatalogoPresente[]   = [];
  showGiftForm   = false;
  giftForm: CatalogoPresenteForm      = { nome: '', descricao: '', valor: 0 };

  // Edição de item do catálogo
  editingPresente: CatalogoPresente | null = null;
  editGiftForm: CatalogoPresenteForm       = { nome: '', descricao: '', valor: 0 };

  // ── Presentes recebidos ───────────────────
  presentesRecebidos: PresenteRecebidoDTO[] = [];

  // ── Convites ──────────────────────────────
  convites:        ConviteResponse[] = [];
  showConviteForm  = false;
  conviteForm      = { codigo: '', familia: '', convidadosStr: '' };

  // Edição de convite
  editingConvite: ConviteResponse | null = null;
  editConviteForm = { codigo: '', familia: '' };

  // Edição de convidado individual
  editingConvidado: { conviteId: number; convidado: Convidado } | null = null;
  editConvidadoNome = '';

  // ── Computed ──────────────────────────────
  get totalArrecadado(): number {
    return this.presentesRecebidos
      .filter(p => p.statusPagamento === 'PAGO')
      .reduce((s, p) => s + p.total, 0);
  }

  get mensagens(): PresenteRecebidoDTO[] {
    return this.presentesRecebidos.filter(p => p.mensagem && p.mensagem.trim());
  }

  get ultimosPresentes(): PresenteRecebidoDTO[] {
    return [...this.presentesRecebidos].reverse().slice(0, 5);
  }

  get confirmados(): number {
    return this.convites.flatMap(c => c.convidados)
      .filter(g => g.status === 'CONFIRMADO').length;
  }

  get pendentes(): number {
    return this.convites.flatMap(c => c.convidados)
      .filter(g => g.status === 'PENDENTE').length;
  }

  get talvez(): number {
    return this.convites.flatMap(c => c.convidados)
      .filter(g => g.status === 'TALVEZ').length;
  }

  get naoVem(): number {
    return this.convites.flatMap(c => c.convidados)
      .filter(g => g.status === 'NAO_VEM').length;
  }

  constructor(
    public  auth:              AuthService,
    private catalogoSvc:       CatalogoPresenteService,
    private presenteRecebidoS: PresenteRecebidoService,
    private conviteSvc:        ConviteService,
    private toastSvc:          ToastService,
  ) {}

  ngOnInit(): void {
    if (this.auth.isLoggedIn()) this.loadData();
  }

  // ── Login ─────────────────────────────────
  login(): void {
    const req: AdminLoginRequest = { username: this.loginUser, password: this.loginPass };
    this.logging  = true;
    this.loginErr = '';
    this.auth.login(req).subscribe({
      next:  () => { this.logging = false; this.loadData(); },
      error: () => { this.logging = false; this.loginErr = 'Usuário ou senha incorretos.'; },
    });
  }

  logout(): void { this.auth.logout(); }

  // ── Dados ─────────────────────────────────
  loadData(): void {
    this.catalogoSvc.listar()
      .subscribe({ next: c => this.catalogo = c, error: () => {} });
    this.presenteRecebidoS.listar()
      .subscribe({ next: p => this.presentesRecebidos = p, error: () => {} });
    this.conviteSvc.listar()
      .subscribe({ next: c => this.convites = c, error: () => {} });
  }

  setTab(tab: AdminTab): void {
    this.activeTab = tab;
    this.cancelarEdicaoPresente();
    this.cancelarEdicaoConvite();
    this.cancelarEdicaoConvidado();
  }

  // ════════════════════════════════════════
  // CATÁLOGO — Criar
  // ════════════════════════════════════════
  addPresente(): void {
    if (!this.giftForm.nome.trim() || !this.giftForm.valor) {
      this.toastSvc.error('Preencha nome e valor!'); return;
    }
    this.catalogoSvc.criar({ ...this.giftForm }).subscribe({
      next: p => {
        this.catalogo     = [...this.catalogo, p];
        this.showGiftForm = false;
        this.giftForm     = { nome: '', descricao: '', valor: 0 };
        this.toastSvc.success('"' + p.nome + '" adicionado! 🎁');
      },
      error: () => this.toastSvc.error('Erro ao adicionar presente.'),
    });
  }

  // CATÁLOGO — Iniciar edição
  iniciarEdicaoPresente(p: CatalogoPresente): void {
    this.editingPresente = p;
    this.editGiftForm    = { nome: p.nome, descricao: p.descricao, valor: p.valor, imagemUrl: p.imagemUrl };
    this.showGiftForm    = false; // fecha form de criação se estiver aberto
  }

  cancelarEdicaoPresente(): void {
    this.editingPresente = null;
    this.editGiftForm    = { nome: '', descricao: '', valor: 0 };
  }

  // CATÁLOGO — Salvar edição
  salvarEdicaoPresente(): void {
    if (!this.editingPresente) return;
    if (!this.editGiftForm.nome.trim() || !this.editGiftForm.valor) {
      this.toastSvc.error('Preencha nome e valor!'); return;
    }
    this.catalogoSvc.atualizar(this.editingPresente.id, { ...this.editGiftForm }).subscribe({
      next: atualizado => {
        this.catalogo = this.catalogo.map(p =>
          p.id === atualizado.id ? atualizado : p
        );
        this.cancelarEdicaoPresente();
        this.toastSvc.success('"' + atualizado.nome + '" atualizado! ✓');
      },
      error: () => this.toastSvc.error('Erro ao atualizar presente.'),
    });
  }

  // CATÁLOGO — Remover
  removePresente(id: number): void {
    if (!confirm('Remover este presente do catálogo?')) return;
    this.catalogoSvc.deletar(id).subscribe({
      next: () => {
        this.catalogo = this.catalogo.filter(p => p.id !== id);
        this.toastSvc.success('Presente removido.');
      },
      error: () => this.toastSvc.error('Erro ao remover.'),
    });
  }

  // ════════════════════════════════════════
  // CONVITES — Criar
  // ════════════════════════════════════════
  addConvite(): void {
    if (!this.conviteForm.codigo.trim() || !this.conviteForm.familia.trim()) {
      this.toastSvc.error('Preencha código e família!'); return;
    }
    const convidados = this.conviteForm.convidadosStr
      .split('\n').map(s => s.trim()).filter(s => s.length > 0);
    if (!convidados.length) {
      this.toastSvc.error('Adicione pelo menos um convidado!'); return;
    }
    const dto: ConviteAdminRequest = {
      codigo:     this.conviteForm.codigo.toUpperCase(),
      familia:    this.conviteForm.familia,
      convidados,
    };
    this.conviteSvc.criar(dto).subscribe({
      next: c => {
        this.convites        = [...this.convites, c];
        this.showConviteForm = false;
        this.conviteForm     = { codigo: '', familia: '', convidadosStr: '' };
        this.toastSvc.success('Convite ' + c.codigo + ' criado!');
      },
      error: () => this.toastSvc.error('Erro ao criar convite.'),
    });
  }

  // CONVITES — Iniciar edição (código e família)
  iniciarEdicaoConvite(c: ConviteResponse): void {
    this.editingConvite  = c;
    this.editConviteForm = { codigo: c.codigo, familia: c.familia };
  }

  cancelarEdicaoConvite(): void {
    this.editingConvite  = null;
    this.editConviteForm = { codigo: '', familia: '' };
  }

  // CONVITES — Salvar edição
  salvarEdicaoConvite(): void {
    if (!this.editingConvite) return;
    if (!this.editConviteForm.codigo.trim() || !this.editConviteForm.familia.trim()) {
      this.toastSvc.error('Preencha código e família!'); return;
    }
    this.conviteSvc.atualizar(this.editingConvite.id, {
      codigo:     this.editConviteForm.codigo.toUpperCase(),
      familia:    this.editConviteForm.familia,
      convidados: this.editingConvite.convidados.map(g => g.nome),
    }).subscribe({
      next: atualizado => {
        this.convites = this.convites.map(c =>
          c.id === atualizado.id ? atualizado : c
        );
        this.cancelarEdicaoConvite();
        this.toastSvc.success('Convite atualizado!');
      },
      error: () => this.toastSvc.error('Erro ao atualizar convite.'),
    });
  }

  // CONVITES — Remover
  removeConvite(id: number): void {
    if (!confirm('Remover este convite e todos seus convidados?')) return;
    this.conviteSvc.deletar(id).subscribe({
      next: () => {
        this.convites = this.convites.filter(c => c.id !== id);
        this.toastSvc.success('Convite removido.');
      },
      error: () => this.toastSvc.error('Erro ao remover convite.'),
    });
  }

  // ════════════════════════════════════════
  // CONVIDADOS — edição individual
  // ════════════════════════════════════════
  iniciarEdicaoConvidado(conviteId: number, convidado: Convidado): void {
    this.editingConvidado  = { conviteId, convidado };
    this.editConvidadoNome = convidado.nome;
  }

  cancelarEdicaoConvidado(): void {
    this.editingConvidado  = null;
    this.editConvidadoNome = '';
  }

  salvarEdicaoConvidado(): void {
    if (!this.editingConvidado) return;
    if (!this.editConvidadoNome.trim()) {
      this.toastSvc.error('O nome não pode ser vazio!'); return;
    }
    const { conviteId, convidado } = this.editingConvidado;
    this.conviteSvc.atualizarConvidado(conviteId, convidado.id, this.editConvidadoNome.trim())
      .subscribe({
        next: () => {
          this.convites = this.convites.map(c => {
            if (c.id !== conviteId) return c;
            return {
              ...c,
              convidados: c.convidados.map(g =>
                g.id === convidado.id ? { ...g, nome: this.editConvidadoNome.trim() } : g
              ),
            };
          });
          this.cancelarEdicaoConvidado();
          this.toastSvc.success('Convidado atualizado!');
        },
        error: () => this.toastSvc.error('Erro ao atualizar convidado.'),
      });
  }

  removerConvidado(conviteId: number, convidadoId: number, nome: string): void {
    if (!confirm('Remover ' + nome + ' deste convite?')) return;
    this.conviteSvc.removerConvidado(conviteId, convidadoId).subscribe({
      next: () => {
        this.convites = this.convites.map(c => {
          if (c.id !== conviteId) return c;
          return { ...c, convidados: c.convidados.filter(g => g.id !== convidadoId) };
        });
        this.toastSvc.success(nome + ' removido.');
      },
      error: () => this.toastSvc.error('Erro ao remover convidado.'),
    });
  }

  // ── Helpers ───────────────────────────────
  confirmadosCount(convite: ConviteResponse): number {
    return convite.convidados.filter(g => g.status === 'CONFIRMADO').length;
  }

  isEditandoPresente(id: number): boolean {
    return this.editingPresente?.id === id;
  }

  isEditandoConvite(id: number): boolean {
    return this.editingConvite?.id === id;
  }

  isEditandoConvidado(id: number): boolean {
    return this.editingConvidado?.convidado.id === id;
  }

  statusClass(status: string): string {
    const map: Record<string, string> = {
      CONFIRMADO: 'badge--confirm', TALVEZ: 'badge--maybe',
      NAO_VEM:    'badge--decline', PENDENTE: 'badge--pending',
    };
    return map[status] ?? '';
  }

  statusLabel(status: string): string {
    const map: Record<string, string> = {
      CONFIRMADO: '✓ Confirmado', TALVEZ: '? Talvez',
      NAO_VEM:    '✗ Não vem',   PENDENTE: '⏳ Pendente',
    };
    return map[status] ?? status;
  }

  statusPagLabel(status: string): string {
    const map: Record<string, string> = {
      PAGO: '✓ Pago', PENDENTE: '⏳ Pendente',
      EXPIRADO: '✗ Expirado', RECUSADO: '✗ Recusado',
    };
    return map[status] ?? status;
  }

  pagamentoLabel(forma: string): string {
    return forma === 'PIX' ? '📱 Pix' : '💳 Cartão';
  }
}
